import{_ as r,o as e,c as i,ag as s}from"./chunks/framework.f_9xDHrT.js";const p=JSON.parse('{"title":"使用说明","description":"使用 MissFisher 启动预设、鱼王、出海垂钓、宇宙探索与云冠群岛相关模式。","frontmatter":{"title":"使用说明","description":"使用 MissFisher 启动预设、鱼王、出海垂钓、宇宙探索与云冠群岛相关模式。"},"headers":[],"relativePath":"manual/usage.md","filePath":"manual/usage.md","lastUpdated":null}'),a={name:"manual/usage.md"};function l(d,t,o,h,n,c){return e(),i("div",null,[...t[0]||(t[0]=[s(`<h1 id="使用说明" tabindex="-1">使用说明 <a class="header-anchor" href="#使用说明" aria-label="Permalink to &quot;使用说明&quot;">​</a></h1><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p></p><ul><li><strong>MissFisher 只能钓鱼：</strong><br> MissFisher 不能自动刺鱼，也不能帮你完全自动地一键完成所有钓鱼目标，无法独自进行 24 小时全天候挂机并处理所有情况。</li><li><strong>MissFisher 不是万能的：</strong><br> 不能教你学会钓鱼，也不能控制你从小白变成高手。<s>是的 MissFisher 不会脑控你。</s></li><li><strong>内容不是新手攻略：</strong><br> 本文假设你已对游戏中的系统和钓鱼玩法有基本了解。</li></ul></div><p>如果你完全不懂钓鱼，这里有一些有用的链接：</p><ul><li><p><strong>灰机 Wiki：</strong></p><ul><li><strong><a href="https://ff14.huijiwiki.com/wiki/%E6%8D%95%E9%B1%BC%E4%BA%BA" target="_blank" rel="noreferrer">灰机 Wiki 的捕鱼人页面</a></strong></li></ul></li><li><p><strong>NGA：</strong></p><ul><li><strong><a href="https://nga.178.com/read.php?tid=41249538&amp;authorid=60554200" target="_blank" rel="noreferrer">捕鱼人大型整合攻略</a></strong></li><li><strong><a href="https://nga.178.com/read.php?tid=42046664&amp;authorid=60300883" target="_blank" rel="noreferrer">7.0捕鱼人大地票据指南</a></strong></li><li><strong><a href="https://nga.178.com/read.php?tid=45353336" target="_blank" rel="noreferrer">捕鱼人练级推荐之宇宙探索</a></strong></li><li><strong><a href="https://nga.178.com/read.php?tid=37816417&amp;authorid=60919598" target="_blank" rel="noreferrer">捕鱼人升级路线研究与推荐</a></strong></li></ul></li></ul><hr><h2 id="missfisher-的预设" tabindex="-1">MissFisher 的预设 <a class="header-anchor" href="#missfisher-的预设" aria-label="Permalink to &quot;MissFisher 的预设&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p></p><ul><li><strong>预设是 MissFisher 实现自动钓鱼的关键：</strong><br> 在启动任何自动模式或预设前，你应该确保预设已经同步到最新版。<br> 你可以在主界面的设置页找到 <code>同步</code> 按钮，点击它即可开始将预设从本仓库同步到本地。</li><li><strong>MissFisher 会自动同步预设：</strong><br> 若有以下情况，MissFisher 将自动同步预设： <ul><li>新版本的 MissFisher 初始化时</li><li>初始化时与上次自动同步相隔 1 天时</li></ul></li></ul></div><p>MissFisher 的预设由特殊的钓法表达式组成，目前仅由作者一人维护：<a href="https://docs.qq.com/sheet/DVlNaQ012amF4SW1G?tab=yirja0" target="_blank" rel="noreferrer">腾讯表格-在线预设表格</a></p><p>你也可以在主界面点击预设页签来切换到预设页，使用预设页下的钓法表达式生成器来图形化地编写一条钓法表达式。</p><p>修改预设中的参数或钓法（暂缺校订）：<a href="https://blackcleaverloli.github.io/MissFisher/guide/quick-edit" target="_blank" rel="noreferrer">钓法表达式快速修改指南</a>。</p><p>如果你是经验老到的捕鱼人且发现自动时的钓法与理想钓法不符，欢迎反馈。</p><hr><h2 id="用-missfisher-钓特定的鱼类" tabindex="-1">用 MissFisher 钓特定的鱼类 <a class="header-anchor" href="#用-missfisher-钓特定的鱼类" aria-label="Permalink to &quot;用 MissFisher 钓特定的鱼类&quot;">​</a></h2><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p></p><ul><li><strong>MissFisher 不能帮你一键收集所有图鉴</strong><br> 你只能自己查看攻略网站或相关插件来确认鱼类所需条件的窗口期、自己准备钓饵和管理背包空间。</li><li><strong>别浪费自己的时间</strong><br> 请在捕鱼人升到满级，且在完成职业任务以学习技能 耐心II 后，再尝试钓钓场之王（鱼王）。</li></ul></div><h3 id="准备好钓鱼" tabindex="-1">准备好钓鱼： <a class="header-anchor" href="#准备好钓鱼" aria-label="Permalink to &quot;准备好钓鱼：&quot;">​</a></h3><ol><li>访问 <a href="https://fish.ffmomola.com/ng/#/fishing" target="_blank" rel="noreferrer">鱼糕</a> 或一些攻略，查看要钓的鱼类的窗口期等信息</li><li>复制要钓的鱼类名称，将其填入 MissFisher 主界面的主页右下角的预设名输入框</li><li>点击查看按钮，MissFisher 会在消息窗口显示所需钓饵</li><li>准备好所需钓饵和至少 5 ~ 10 格背包空间</li></ol><h3 id="前往钓场" tabindex="-1">前往钓场： <a class="header-anchor" href="#前往钓场" aria-label="Permalink to &quot;前往钓场：&quot;">​</a></h3><ol><li>按住 Ctrl 对预设名输入框按下鼠标滚轮（或点击前往钓场，如有），如果当前不在对应钓场的地图，MissFisher 会发起传送，然后调用其他插件来自动前往钓场</li><li>操控角色靠近钓场的可钓地面边缘，使角色面朝钓场可垂钓区域直到技能抛竿亮起</li></ol><h3 id="启动" tabindex="-1">启动！ <a class="header-anchor" href="#启动" aria-label="Permalink to &quot;启动！&quot;">​</a></h3><ol><li>对预设名输入框双击鼠标左键，或切换到预设模式点击启动按钮，MissFisher 会启动可用的对应预设</li></ol><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p></p><ul><li><strong>对于有窗口期限制的鱼类：</strong><br> 除非预设的备注中有特殊说明，否则可在窗口期到来前启动， MissFisher 将自动准备相应技能资源和状态效果。</li></ul></div><h3 id="鱼眼预设" tabindex="-1">鱼眼预设 <a class="header-anchor" href="#鱼眼预设" aria-label="Permalink to &quot;鱼眼预设&quot;">​</a></h3><p>MissFisher 有部分鱼类的使用特殊技能鱼眼的预设，一般而言它们以鱼名开头并以 <code>鱼眼</code> 或 <code>-Fish Eyes</code> 结尾以表示这是鱼眼预设。</p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p></p><ul><li><strong>鱼眼的游戏机制请参考：</strong><br><a href="https://ff14.huijiwiki.com/wiki/%E6%8D%95%E9%B1%BC%E4%BA%BA#%E5%A4%A9%E6%B0%94%E3%80%81%E6%97%B6%E9%97%B4%E4%B8%8E%E9%B1%BC%E7%9C%BC" target="_blank" rel="noreferrer">灰机 Wiki-捕鱼人-天气、时间与鱼眼</a></li></ul></div><hr><h2 id="用-missfisher-出海垂钓" tabindex="-1">用 MissFisher 出海垂钓 <a class="header-anchor" href="#用-missfisher-出海垂钓" aria-label="Permalink to &quot;用 MissFisher 出海垂钓&quot;">​</a></h2><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>如果你不知道出海垂钓是什么，请看 <a href="https://ff14.huijiwiki.com/wiki/%E5%87%BA%E6%B5%B7%E5%9E%82%E9%92%93" target="_blank" rel="noreferrer">灰机 Wiki-出海垂钓</a></p></div><p>你可使用 MissFisher 中的下列模式来自动出海垂钓：</p><table tabindex="0"><thead><tr><th>模式</th><th>主要目的</th><th>备注</th></tr></thead><tbody><tr><td><em>冲分</em></td><td>称号【海王】【世界级钓手】</td><td>渔分的高低比较看运气</td></tr><tr><td><em>蓝鱼</em></td><td>点亮蓝色稀有度鱼类的图鉴</td><td>会尝试钓航线中所有可钓的蓝鱼，当已无蓝鱼可钓时将使用冲分手法</td></tr><tr><td><em>种类x</em></td><td>航线预报中角标x对应的数量类成就&amp;称号</td><td>请留意选择的模式<br>部分数量类成就需要组队才能完成</td></tr><tr><td><em>练级</em></td><td>在出海垂钓中提升等级</td><td>如果你已完成 6.x 版本的主线任务且喜欢折腾<br>请尝试 <a href="https://nga.178.com/read.php?tid=45353336" target="_blank" rel="noreferrer">在宇宙探索练级</a></td></tr><tr><td><em>耐力xx</em></td><td>全自动地完成海钓循环</td><td>现支持：冲分/蓝鱼/练级</td></tr></tbody></table><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p></p><ul><li><strong>MissFisher 内置了完备的自动预设切换：</strong><br> 启动后会全自动完成整场出海垂钓任务。且会按情况灵活地变化手法以达成目的需求。</li></ul></div><h3 id="使用-missfisher-出海垂钓的步骤" tabindex="-1">使用 MissFisher 出海垂钓的步骤： <a class="header-anchor" href="#使用-missfisher-出海垂钓的步骤" aria-label="Permalink to &quot;使用 MissFisher 出海垂钓的步骤：&quot;">​</a></h3><h4 id="点启动就行" tabindex="-1">点启动就行： <a class="header-anchor" href="#点启动就行" aria-label="Permalink to &quot;点启动就行：&quot;">​</a></h4><p>切换到带 耐力 前缀的模式，点击启动按钮即可。</p><p>如果运行所需的条件不符合，MissFisher 将提示所需的条件。请手动满足可能未满足的运行所需条件，然后再次点击启动按钮。</p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p></p><ul><li><strong>自由地查看想去的航线：</strong><br> 选择主界面的航线页签来查看航线预报；或者 <a href="https://fish.ffmomola.com/ng/#/oceanFishing" target="_blank" rel="noreferrer">访问鱼糕</a></li></ul></div><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p></p><ul><li><strong>使用对应的种类模式：</strong><br> 选择好不同的种类模式后，将鼠标移动到启动按钮上查看悬浮提示上的对应标签</li><li><strong>种类模式对应的数量类成就：</strong><br> 在出海垂钓相关的成就中，有一类数量类成就及其奖励称号，必须在单场出海垂钓任务中单人或组队钓到指定数量的同分类鱼类时，才能获得。 <ul><li>例如成就「气鲀四海」，要求小队全体合计钓到250只以上的鲀类</li><li>例如成就「大虾可重新来过」，要求个人合计钓到50只以上的虾类</li><li>其他详见 <a href="https://ff14.huijiwiki.com/wiki/%E5%87%BA%E6%B5%B7%E5%9E%82%E9%92%93#%E5%A5%96%E5%8A%B1" target="_blank" rel="noreferrer">灰机Wiki的相关章节</a></li></ul></li></ul></div><hr><h2 id="missfisher-中的航线预报" tabindex="-1">MissFisher 中的航线预报 <a class="header-anchor" href="#missfisher-中的航线预报" aria-label="Permalink to &quot;MissFisher 中的航线预报&quot;">​</a></h2><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>你可以在主界面选择 航线 页签来查看航线预报。</p></div><p>MissFisher 的 1 组航线预报由 2 行内容组成：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>11-02 02:00　「索蒂斯（火萤）」「依拉丝莫龙（重铁板钩）」　梅尔托尔海峡南(昏)》加拉迪翁湾(夜)》梅尔托尔海峡北(日)　04  </span></span>
<span class="line"><span>　　　　　　　「四海大宝贝¹」「塔尼瓦（青花鱼块）」　　　　 妖歌海海面(日)》黄金港近海(昏)》无二江下游(夜)</span></span></code></pre></div><ul><li><p>第 1 行是近海航线，第 2 行是远海航线。</p><ul><li>分别对应登记出海垂钓选择航线时的第 1 项和第 2 项</li></ul></li><li><p>每列从左到右分别是：开放登记时间、航线标识、海域与时间带、在 MissFisher 的内部序号。</p></li></ul><h3 id="航线预报中的航线标识" tabindex="-1">航线预报中的航线标识 <a class="header-anchor" href="#航线预报中的航线标识" aria-label="Permalink to &quot;航线预报中的航线标识&quot;">​</a></h3><p>航线预报中的航线标识灵感和顺序来自 <a href="https://fish.ffmomola.com/ng/#/oceanFishing" target="_blank" rel="noreferrer">鱼糕-出海垂钓航线</a>，你也可以访问鱼糕获取特定航线的更多信息。</p><p>亦有部分鱼糕中没有的标识，系笔者在开发 Triggernometry 版本时在数月的维护和测试中得出的。</p><table tabindex="0"><thead><tr><th>类型</th><th>标识</th><th>备注</th></tr></thead><tbody><tr><td>渔分</td><td>「挑战高分」</td><td>渔分上限较高，也适合获取「海王」称号&amp;成就；<br>全自动下少数情况能获得 3~4 万分的高分；<br>运气差时可能只有几千。</td></tr><tr><td>远洋<br>渔分</td><td>「深洋之劫」</td><td>适合获取「深洋之劫」称号&amp;成就的远洋航线</td></tr><tr><td>渔分</td><td>「世界级钓手」</td><td>分数下限较高；<br>适合获取「世界级钓手」称号&amp;成就的航线。</td></tr><tr><td>近海<br>蓝鱼</td><td>「盾齿龙」<br>「海洋蟾蜍（潮虫）」<br>「依拉丝莫龙（重铁板钩）」<br>「哈弗古法（乌贼丝）」<br>「珊瑚蝠鲼（小虾肉笼）」<br>「索蒂斯（火萤）」<br>「石骨鱼（沟鼠尾巴）」</td><td>圆括号中是需要额外携带的钓饵</td></tr><tr><td>远洋<br>蓝鱼</td><td>「琉璃龙」<br>「狱之蟹（乌贼丝）」<br>「塔尼瓦（青花鱼块）」<br>「梅泉宝龟（石蝇幼虫）」</td><td>圆括号中是需要额外携带的钓饵</td></tr><tr><td>近海<br>数量类<br>成就</td><td>「水母狂魔¹」<br>「横路不通¹」<br>「只有我最鳐摆²」<br>「捕鲨人¹」<br>「龙马惊神¹」<br>「只有我最鳐摆¹」<br>「气鲀四海¹」<br>「八爪旅人¹」</td><td>角标 <code>¹</code> <code>²</code>：<br>表示需求为该标识时应使用的种类模式<br><code>¹</code> = 种类1<br><code>²</code> = 种类2</td></tr><tr><td>远洋<br>数量类<br>成就</td><td>「大虾可重新来过²」<br>「大虾可重新来过¹」<br>「四海大宝贝¹」<br>「鱿型中队精英¹」</td><td>角标 <code>¹</code> <code>²</code>：<br>表示需求为该标识时应使用的种类模式<br><code>¹</code> = 种类1<br><code>²</code> = 种类2</td></tr></tbody></table><hr><h2 id="钓出海垂钓中的特定鱼类" tabindex="-1">钓出海垂钓中的特定鱼类 <a class="header-anchor" href="#钓出海垂钓中的特定鱼类" aria-label="Permalink to &quot;钓出海垂钓中的特定鱼类&quot;">​</a></h2><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p></p><ul><li><strong>MissFisher 没有如“图鉴模式”的功能</strong><br> 因此，对于幻海流时的非蓝色稀有度鱼类，你只能自己手动尝试钓到。</li><li><strong>MissFisher 有非幻海流时绿色稀有度鱼类的预设</strong><br> 但不能自动识别并切换到对应钓法，你必须手动在对应鱼类的出现海域，并在的合适时机启动对应的预设。</li></ul></div><h3 id="钓非幻海流时的绿色稀有度鱼类" tabindex="-1">钓非幻海流时的绿色稀有度鱼类 <a class="header-anchor" href="#钓非幻海流时的绿色稀有度鱼类" aria-label="Permalink to &quot;钓非幻海流时的绿色稀有度鱼类&quot;">​</a></h3><p>你可以在主界面主页的右下角找到预设输入框，将非幻海流时的绿色稀有度鱼类名称输入，即可启动预设。</p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p></p><ul><li><strong>在正确的航线、海域以及时机启动预设</strong><br> 你应该注意钓到鱼类所需的条件，并不是所有时间的任何海域都能钓到特定鱼类。</li></ul></div><hr><h2 id="用-missfisher-完成宇宙探索任务" tabindex="-1">用 MissFisher 完成宇宙探索任务 <a class="header-anchor" href="#用-missfisher-完成宇宙探索任务" aria-label="Permalink to &quot;用 MissFisher 完成宇宙探索任务&quot;">​</a></h2><p>在使用捕鱼人接取宇宙探索任务的数秒后，MissFisher 将自动识别任务并启动对应预设。</p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p></p><ul><li><strong>建议安装的插件：ICE</strong><br> ICE 可以自动刷取、接取和提交特定任务。<br> 如果你还未安装，你可以在 MissFisher 的设置页中找到 ICE 的仓库链接。</li></ul></div><h2 id="满足各类宇宙探索需求" tabindex="-1">满足各类宇宙探索需求 <a class="header-anchor" href="#满足各类宇宙探索需求" aria-label="Permalink to &quot;满足各类宇宙探索需求&quot;">​</a></h2><div class="caution custom-block github-alert"><p class="custom-block-title">CAUTION</p><p></p><ul><li><strong>本章节的部分内容可能过时：</strong><br> 如有建议，欢迎反馈。</li></ul></div><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p></p><ul><li><strong>宇宙探索相关的有用链接：</strong><br> [<a href="https://actff1.web.sdo.com/project/20250619cosmicexploration/v4kjfz92uewnum597r5wr0fa3km7bg/index.html#/cosmic_exploration" target="_blank" rel="noreferrer">中国服宇宙探索游玩指南</a>]<br> [<a href="https://ff14.huijiwiki.com/wiki/%E5%AE%87%E5%AE%99%E6%8E%A2%E7%B4%A2" target="_blank" rel="noreferrer">灰机 Wiki 的宇宙探索页面</a>]</li><li><strong>开始探索：</strong><br> 如果你需要制作捕鱼人的宇宙探索工具，先从憧憬湾的探索任务开始，直到中级阶段（中级I-1）再前往法恩娜行星；在高级阶段（高级A-1）时，前往俄匊斯行星。</li><li><strong>留意可接取的紧急、时间限定与天气限定任务：</strong><br> 通常而言它们易于完成，且会给予大量信用点 / 技巧点。（可能有误）</li></ul></div><p>满足各类需求效率较高的任务：</p><table tabindex="0"><thead><tr><th style="text-align:center;">探索地点</th><th>类别</th><th>探索任务名</th><th>说明</th></tr></thead><tbody><tr><td style="text-align:center;">憧憬湾</td><td>C 类</td><td>协助调查基地西北侧的水质</td><td>可以高效获取数据 I、数据 II，<br>也可以刷月面信用点</td></tr><tr><td style="text-align:center;">憧憬湾</td><td>A 类</td><td>检验钓场的多样性</td><td>可以高效获取数据 III、数据 IV，<br>也可以刷宇宙信用点和技巧点</td></tr><tr><td style="text-align:center;">憧憬湾</td><td>A 类</td><td>采集魔泉环境的样本</td><td>【限时】可以高效获取数据 III、数据 IV，<br>也可以刷宇宙信用点和技巧点</td></tr><tr><td style="text-align:center;">憧憬湾</td><td>A 类</td><td>【高难】制作改良版月凝胶</td><td>可以高效获取捕鱼人技巧点，<br>需要你的炼金术师职业有正常的等级、<br>技能和已部分禁忌镶嵌的新装备（对于7.4），<br>且需要使用生产职业用的食品</td></tr><tr><td style="text-align:center;">法恩娜</td><td>C 类</td><td>高效筹备水产食品</td><td>可以高效获取数据 I、数据 II、数据 III</td></tr><tr><td style="text-align:center;">法恩娜</td><td>A 类</td><td>支援利用水产资源开发精密镜片</td><td>可以高效获取数据 III、数据 IV、数据 V</td></tr><tr><td style="text-align:center;">法恩娜</td><td>A 类</td><td>【高难】大型水产资源的捕获调查</td><td>可以高效获取数据 II、数据 IV、数据 V</td></tr><tr><td style="text-align:center;">俄匊斯</td><td>B 类</td><td>调查养殖鱼的重力异常适应性</td><td>可以高效获取数据 II、数据 III、数据 IV</td></tr><tr><td style="text-align:center;">俄匊斯</td><td>A 类</td><td>调查海洋水产品的可食用性</td><td>可以高效获取数据 I、数据 V、数据 VI</td></tr></tbody></table><hr><h2 id="用-missfisher-满足云冠群岛相关需求" tabindex="-1">用 MissFisher 满足云冠群岛相关需求 <a class="header-anchor" href="#用-missfisher-满足云冠群岛相关需求" aria-label="Permalink to &quot;用 MissFisher 满足云冠群岛相关需求&quot;">​</a></h2><p>MissFisher 有一些模式可帮助达成相关成就：</p><table tabindex="0"><thead><tr><th style="text-align:center;">空岛成就名</th><th style="text-align:center;">对应的模式</th><th>所需的钓饵</th></tr></thead><tbody><tr><td style="text-align:center;">新巢居住区的捕鱼人</td><td style="text-align:center;">空岛二期</td><td>云冠浮游虫</td></tr><tr><td style="text-align:center;">落羽商业区的捕鱼人</td><td style="text-align:center;">空岛三期</td><td>云冠大蚊</td></tr><tr><td style="text-align:center;">升歌文化区的捕鱼人</td><td style="text-align:center;">空岛四期</td><td>云冠大蚊、云冠气球虫</td></tr><tr><td style="text-align:center;">天穹街的捕鱼人</td><td style="text-align:center;">空岛技巧点</td><td>云冠大蚊、云冠气球虫</td></tr><tr><td style="text-align:center;">观天的捕鱼人</td><td style="text-align:center;">空岛绿鱼</td><td>万能拟饵、云冠大蚊、云冠气球虫、云冠红气球虫</td></tr></tbody></table><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p></p><ul><li><strong>建议的捕鱼人伊修加德重建成就完成顺序：</strong><br> 特供绿鱼 → 二期特供 &amp; 三期特供 → 技巧点/四期特供</li></ul></div><h2 id="使用云冠群岛模式的步骤" tabindex="-1">使用云冠群岛模式的步骤 <a class="header-anchor" href="#使用云冠群岛模式的步骤" aria-label="Permalink to &quot;使用云冠群岛模式的步骤&quot;">​</a></h2><h3 id="前往云冠群岛" tabindex="-1">前往云冠群岛 <a class="header-anchor" href="#前往云冠群岛" aria-label="Permalink to &quot;前往云冠群岛&quot;">​</a></h3><ol><li>准备好至少 6 ~ 10 格背包空间</li><li>在 MissFisher 主界面主页选择好空岛相关模式</li><li>前往云冠群岛</li></ol><h3 id="启动空岛模式" tabindex="-1">启动空岛模式 <a class="header-anchor" href="#启动空岛模式" aria-label="Permalink to &quot;启动空岛模式&quot;">​</a></h3><ol><li>启动空岛模式时，MissFisher 会尝试检查是否在钓场范围内，如果否，将尝试前往对应钓场</li><li>当角色处在对应钓场时，操控角色靠近空岛边缘，使角色面朝空岛可钓鱼区域直到技能抛竿可用</li><li>点击启动按钮</li></ol><hr><h2 id="用-missfisher-练级" tabindex="-1">用 MissFisher 练级？ <a class="header-anchor" href="#用-missfisher-练级" aria-label="Permalink to &quot;用 MissFisher 练级？&quot;">​</a></h2><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p></p><ul><li><strong>缺乏特别支持：</strong><br> 练级过程只占游戏中钓鱼玩法的很少一部分，且难以重复测试效果。<br> 因此，MissFisher 的自动行为并没有专门针对未满级的捕鱼人或练级过程进行完全的优化。</li></ul></div><p>你可以在主界面上的模式下拉菜单中找到 MissFisher 的练级模式，但该模式在出海垂钓外的行为只是使用「万能拟饵」来抛竿，然后对任何咬饵使用普通提钩。</p><p>如果你不愿意手动钓鱼，请看：<a href="#用-missfisher-出海垂钓">用 MissFisher 出海垂钓</a>。</p><p>否则，你可以参考攻略：<a href="https://nga.178.com/read.php?tid=37816417&amp;authorid=60919598" target="_blank" rel="noreferrer">NGA-捕鱼人升级路线研究与推荐</a>。</p><p>如果你觉得 MissFisher 可以新增预设以减少在练级过程中的重复劳动，欢迎反馈。</p><hr>`,79)])])}const u=r(a,[["render",l]]);export{p as __pageData,u as default};
